from datetime import datetime
from hashlib import sha256
from collections import defaultdict

class UserInteraction:
    def __init__(self, user_id, interaction_type, timestamp=None):
        self.user_id = user_id
        self.interaction_type = interaction_type
        self.timestamp = timestamp or datetime.now()
        self.hash = self._hash_interaction()

    def _hash_interaction(self):
        data = f"{self.user_id}|{self.interaction_type}|{self.timestamp.isoformat()}"
        return sha256(data.encode()).hexdigest()

class InteractionTracker:
    def __init__(self):
        self.interactions = defaultdict(list)

    def log_interaction(self, user_id, interaction_type):
        interaction = UserInteraction(user_id, interaction_type)
        self.interactions[user_id].append(interaction)

    def get_user_interactions(self, user_id):
        return self.interactions[user_id]

    def get_all_interactions(self):
        return [interaction for interactions in self.interactions.values() for interaction in interactions]

    def get_interactions_by_type(self, interaction_type):
        return [interaction for interaction in self.get_all_interactions() if interaction.interaction_type == interaction_type]

    def delete_user_interactions(self, user_id):
        del self.interactions[user_id]

