from datetime import datetime
from abc import ABC, abstractmethod
from hashlib import sha256
from typing import Dict, List, Union

class Interaction(ABC):
    @abstractmethod
    def to_dict(self) -> dict:
        pass

class Like(Interaction):
    def __init__(self, user_id: str, timestamp: datetime):
        self.user_id = user_id
        self.timestamp = timestamp

    def to_dict(self) -> dict:
        return {
            "type": "like",
            "user_id": sha256(self.user_id.encode()).hexdigest(),
            "timestamp": self.timestamp.isoformat()
        }

class Rating(Interaction):
    def __init__(self, user_id: str, value: float, timestamp: datetime):
        self.user_id = user_id
        self.value = value
        self.timestamp = timestamp

    def to_dict(self) -> dict:
        return {
            "type": "rating",
            "user_id": sha256(self.user_id.encode()).hexdigest(),
            "value": self.value,
            "timestamp": self.timestamp.isoformat()
        }

class Upload(Interaction):
    def __init__(self, user_id: str, timestamp: datetime):
        self.user_id = user_id
        self.timestamp = timestamp

    def to_dict(self) -> dict:
        return {
            "type": "upload",
            "user_id": sha256(self.user_id.encode()).hexdigest(),
            "timestamp": self.timestamp.isoformat()
        }

class SettingsChange(Interaction):
    def __init__(self, user_id: str, changes: Dict[str, Union[str, int, float]], timestamp: datetime):
        self.user_id = user_id
        self.changes = changes
        self.timestamp = timestamp

    def to_dict(self) -> dict:
        return {
            "type": "settings_change",
            "user_id": sha256(self.user_id.encode()).hexdigest(),
            "changes": self.changes,
            "timestamp": self.timestamp.isoformat()
        }

class InteractionTracker:
    def __init__(self):
        self.interactions: List[Interaction] = []

    def track_interaction(self, interaction: Interaction):
        self.interactions.append(interaction)

    def get_interactions(self, user_id: str = None, interaction_type: str = None, start_time: datetime = None, end_time: datetime = None) -> List[dict]:
        filtered_interactions = self.interactions
        if user_id:
            filtered_interactions = [i for i in filtered_interactions if sha256(i.user_id.encode()).hexdigest() == user_id]
        if interaction_type:
            filtered_interactions = [i for i in filtered_interactions if i.__class__.__name__.lower() == interaction_type.lower()]
        if start_time:
            filtered_interactions = [i for i in filtered_interactions if i.timestamp >= start_time]
        if end_time:
            filtered_interactions = [i for i in filtered_interactions if i.timestamp <= end_time]
        return [i.to_dict() for i in filtered_interactions]

