class DataManager:
    def __init__(self, db_file):
        self.db_file = db_file
        self.conn = sqlite3.connect(db_file)
        self.cursor = self.conn.cursor()
        self.create_tables()

    def create_tables(self):
        self.cursor.execute('''CREATE TABLE IF NOT EXISTS operations
                              (id TEXT PRIMARY KEY, type TEXT, data TEXT, timestamp TEXT)''')
        self.conn.commit()

    def add_operation(self, op_type, data):
        op_id = str(uuid.uuid4())
        timestamp = datetime.datetime.now().isoformat()
        self.cursor.execute("INSERT INTO operations (id, type, data, timestamp) VALUES (?, ?, ?, ?)", (op_id, op_type, json.dumps(data), timestamp))
        self.conn.commit()
        return op_id

    def get_operations(self, op_type=None):
        if op_type:
            self.cursor.execute("SELECT * FROM operations WHERE type = ?", (op_type,))
        else:
            self.cursor.execute("SELECT * FROM operations")
        return [self._parse_operation(row) for row in self.cursor.fetchall()]

    def _parse_operation(self, row):
        op_id, op_type, data, timestamp = row
        return {
            "id": op_id,
            "type": op_type,
            "data": json.loads(data),
            "timestamp": timestamp
        }

    def close(self):
        self.conn.close()

