import bcrypt

class SecurityManager:
    def __init__(self, data_dir):
        self.data_dir = data_dir
        self.interactions = []
        self.users = {}
        self.logger = logging.getLogger(__name__)

    def add_interaction(self, user_id, interaction_type, data):
        interaction = {
            'user_id': user_id,
            'interaction_type': interaction_type,
            'data': data,
            'timestamp': datetime.datetime.now()
        }
        self.interactions.append(interaction)
        self.logger.info(f"New interaction recorded: {interaction}")

    def register_user(self, username, password):
        if username in self.users:
            self.logger.warning(f"User '{username}' already exists.")
            return False

        salt = bcrypt.gensalt()
        hashed_password = bcrypt.hashpw(password.encode(), salt)
        user = {
            'username': username,
            'password_hash': hashed_password
        }
        self.users[username] = user
        self.add_interaction(username, 'registration', {})
        self.logger.info(f"New user '{username}' registered.")
        return True

    def authenticate_user(self, username, password):
        if username not in self.users:
            self.logger.warning(f"User '{username}' does not exist.")
            return False

        user = self.users[username]
        if bcrypt.checkpw(password.encode(), user['password_hash']):
            self.add_interaction(username, 'login', {})
            self.logger.info(f"User '{username}' authenticated.")
            return True
        else:
            self.logger.warning(f"Invalid password for user '{username}'.")
            return False

    def log_interaction(self, user_id, interaction_type, data):
        self.add_interaction(user_id, interaction_type, data)

    def get_user_interactions(self, user_id):
        return [i for i in self.interactions if i['user_id'] == user_id]

    def save_data(self):
        if not os.path.exists(self.data_dir):
            os.makedirs(self.data_dir)

        user_data_file = os.path.join(self.data_dir, 'users.txt')
        interaction_data_file = os.path.join(self.data_dir, 'interactions.txt')

        with open(user_data_file, 'w') as f:
            for user in self.users.values():
                f.write(f"{user['username']}:{user['password_hash'].decode()}\n")

        with open(interaction_data_file, 'w') as f:
            for interaction in self.interactions:
                f.write(f"{interaction['user_id']},{interaction['interaction_type']},{interaction['data']},{interaction['timestamp'].isoformat()}\n")

        self.logger.info("Data saved successfully.")

    def load_data(self):
        user_data_file = os.path.join(self.data_dir, 'users.txt')
        interaction_data_file = os.path.join(self.data_dir, 'interactions.txt')

        if os.path.exists(user_data_file):
            with open(user_data_file, 'r') as f:
                for line in f:
                    username, password_hash = line.strip().split(':')
                    self.users[username] = {
                        'username': username,
                        'password_hash': password_hash.encode()
                    }

        if os.path.exists(interaction_data_file):
            with open(interaction_data_file, 'r') as f:
                for line in f:
                    user_id, interaction_type, data, timestamp = line.strip().split(',')
                    interaction = {
                        'user_id': user_id,
                        'interaction_type': interaction_type,
                        'data': data,
                        'timestamp': datetime.datetime.fromisoformat(timestamp)
                    }
                    self.interactions.append(interaction)

        self.logger.info("Data loaded successfully.")

