class Book:
    def __init__(self, title, author, genre, rating, updates):
        self.title = title
        self.author = author
        self.genre = genre
        self.rating = rating
        self.updates = updates

    def serialize(self):
        return {
            "title": self.title,
            "author": self.author,
            "genre": self.genre,
            "rating": self.rating,
            "updates": self.updates
        }

class Library:
    def __init__(self):
        self.books = []

    def add_book(self, book):
        self.books.append(book)

    def update_book(self, book, new_updates):
        book.updates = new_updates

    def get_books_by_genre(self, genre):
        return [book for book in self.books if book.genre == genre]

    def get_top_rated_books(self, n):
        return sorted(self.books, key=lambda x: x.rating, reverse=True)[:n]

    def save_library(self, filename):
        data = [book.serialize() for book in self.books]
        with open(filename, "w") as f:
            json.dump(data, f)

    def load_library(self, filename):
        with open(filename, "r") as f:
            data = json.load(f)
        self.books = [Book(**book_data) for book_data in data]

